(() => {
  'use strict';

  if (window.__pcbw_cf_init) return;
  window.__pcbw_cf_init = true;

  const NS = '__pcbw_cf';
  const STORAGE_KEY = '__pcbw_cf_state';
  const SNAPSHOT_LIMIT = 12;
  const SCHEMA_VERSION = 1;
  const TIMER_REGISTRY = [];

  const CONFIG = {
    ui: {
      frameTitle: 'Chronicle Foundry',
      defaultScreen: 'dashboard'
    },
    sim: {
      travelHoursBase: 6,
      campHoursBase: 8,
      lowSupplyWarningThreshold: 20,
      maxEventHistory: 260,
      eventCooldownTurns: 3
    },
    resourceCaps: {
      food: 220,
      water: 220,
      medicine: 80,
      salvage: 200,
      morale: 100
    }
  };

  const FACTION_LIBRARY = [
    { id: 'river-compact', name: 'River Compact', descriptor: 'Merchants and convoy masters controlling river arteries.' },
    { id: 'embersynod', name: 'Ember Synod', descriptor: 'Archivists and theologians preserving old-world fire-rites.' },
    { id: 'ironwardens', name: 'Iron Wardens', descriptor: 'Militarized frontier marshals obsessed with order.' },
    { id: 'verdant-covenant', name: 'Verdant Covenant', descriptor: 'Biomancers and stewards shaping reclaimed wildlands.' }
  ];

  function ensureCoreObjects() {
    oc.character.customData ??= {};
    oc.character.customData.PUBLIC ??= {};
    oc.thread.customData ??= {};
  }

  function safeJsonClone(value, fallback) {
    try {
      return JSON.parse(JSON.stringify(value));
    } catch (_err) {
      return fallback;
    }
  }

  function hashString(input) {
    let h = 2166136261;
    for (let i = 0; i < input.length; i++) {
      h ^= input.charCodeAt(i);
      h = Math.imul(h, 16777619);
    }
    return (h >>> 0);
  }

  function mulberry32(seed) {
    let a = seed >>> 0;
    return function rand() {
      a += 0x6D2B79F5;
      let t = a;
      t = Math.imul(t ^ (t >>> 15), t | 1);
      t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
      return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
    };
  }

  function pick(rand, list) {
    return list[Math.floor(rand() * list.length) % list.length];
  }

  function clamp(value, min, max) {
    return Math.max(min, Math.min(max, value));
  }

  function nowIso() {
    return new Date().toISOString();
  }

  function getDayPhase(hour) {
    if (hour < 5) return 'deep-night';
    if (hour < 8) return 'dawn';
    if (hour < 12) return 'morning';
    if (hour < 17) return 'afternoon';
    if (hour < 20) return 'dusk';
    return 'night';
  }

  function createRegionGraph(seedString) {
    const rand = mulberry32(hashString(seedString + '|regions'));
    const biomes = ['salt-steppe', 'storm-fens', 'basalt-ridge', 'ghostwood', 'shatterplain', 'ember-canyon', 'mirror-lake'];
    const landmarks = ['collapsed observatory', 'sunken relay tower', 'fractured basilica', 'hydro-forge ruins', 'glass orchard', 'warding monolith'];
    const resources = ['food', 'water', 'medicine', 'salvage'];

    const regionCount = 9;
    const regions = [];
    for (let i = 0; i < regionCount; i++) {
      const id = `rg-${i + 1}`;
      const biome = pick(rand, biomes);
      const danger = Math.floor(rand() * 5) + 1;
      const localResources = [pick(rand, resources), pick(rand, resources)].filter((v, idx, arr) => arr.indexOf(v) === idx);
      const influence = {};
      for (const f of FACTION_LIBRARY) {
        influence[f.id] = clamp(Math.floor(rand() * 81) - 40 + (danger * 2), -100, 100);
      }

      regions.push({
        id,
        name: `Region ${i + 1}`,
        biome,
        danger,
        biomeTags: [biome, pick(rand, ['fog-heavy', 'wind-cut', 'fertile-pockets', 'ruin-dense', 'predator-lanes'])],
        notableLandmarks: [pick(rand, landmarks), pick(rand, landmarks)].filter((v, idx, arr) => arr.indexOf(v) === idx),
        localResources,
        factionInfluence: influence,
        encounterPools: {
          travel: [
            'weather-front',
            'scavenger-contact',
            danger >= 4 ? 'hostile-ambush' : 'hostile-scouts',
            'landmark-discovery'
          ],
          camp: [
            'night-watch-incident',
            'crew-reflection',
            danger >= 4 ? 'perimeter-breach' : 'minor-disturbance',
            'faction-envoy'
          ]
        },
        loreHooks: [
          `The ${biome} once hosted a pre-collapse transit artery.`,
          `Local myths claim ${pick(rand, landmarks)} still emits coded signals.`
        ],
        neighbors: []
      });
    }

    for (let i = 0; i < regionCount; i++) {
      const primary = (i + 1) % regionCount;
      const secondary = (i + 2) % regionCount;
      const back = (i - 1 + regionCount) % regionCount;
      const links = [regions[primary].id, regions[secondary].id, regions[back].id].filter((v, idx, arr) => arr.indexOf(v) === idx);
      regions[i].neighbors = links;
    }

    return regions;
  }

  function createDefaultState(seedSource) {
    const seed = seedSource || `cf-${Date.now()}`;
    const regions = createRegionGraph(seed);
    const startRegion = regions[0]?.id || 'rg-1';
    const rand = mulberry32(hashString(seed + '|party'));

    const names = ['Mara Quell', 'Iven Drax', 'Sera Vale', 'Torin Ash', 'Nyra Holt', 'Kade Mercer', 'Orrin Pike'];
    const roles = ['Pathfinder', 'Quartermaster', 'Medic', 'Surveyor', 'Scout'];
    const traits = ['disciplined', 'superstitious', 'resilient', 'calculating', 'idealistic', 'stoic'];

    const party = Array.from({ length: 4 }).map((_, idx) => ({
      id: `pm-${idx + 1}`,
      name: pick(rand, names) + (idx > 0 ? `-${idx + 1}` : ''),
      role: pick(rand, roles),
      traits: [pick(rand, traits), pick(rand, traits)].filter((v, i, arr) => arr.indexOf(v) === i),
      morale: clamp(60 + Math.floor(rand() * 30), 0, 100),
      fatigue: clamp(10 + Math.floor(rand() * 20), 0, 100),
      conditions: [],
      utility: {
        scouting: clamp(40 + Math.floor(rand() * 50), 1, 100),
        medicine: clamp(20 + Math.floor(rand() * 60), 1, 100),
        engineering: clamp(25 + Math.floor(rand() * 60), 1, 100)
      },
      relationships: {}
    }));

    for (const a of party) {
      for (const b of party) {
        if (a.id === b.id) continue;
        a.relationships[b.id] = clamp(Math.floor(rand() * 51) - 25, -100, 100);
      }
    }

    const factions = {};
    for (const f of FACTION_LIBRARY) {
      factions[f.id] = {
        id: f.id,
        name: f.name,
        descriptor: f.descriptor,
        reputation: clamp(Math.floor(rand() * 31) - 10, -100, 100),
        riskLevel: pick(rand, ['low', 'moderate', 'high']),
        opportunities: [],
        recentConsequences: []
      };
    }

    const baseContracts = [
      {
        id: 'ct-1',
        title: 'Reopen the River Relay',
        issuerFaction: 'river-compact',
        type: 'recovery',
        regionId: regions[2]?.id || startRegion,
        status: 'active',
        progress: 0,
        steps: [
          { id: 'ct-1-s1', text: 'Survey the relay foundations', done: false },
          { id: 'ct-1-s2', text: 'Secure replacement conductor coils', done: false },
          { id: 'ct-1-s3', text: 'Recalibrate the relay beacon', done: false }
        ],
        branching: {
          riskPath: 'Divert power from abandoned ward pylons (higher faction tension).',
          safePath: 'Negotiate sanctioned power allocation (slower completion).'
        },
        rewards: { food: 18, water: 22, salvage: 16, reputation: { 'river-compact': 8 } },
        failureConsequences: { reputation: { 'river-compact': -12, 'ironwardens': -4 }, morale: -6 },
        deadlineDay: 8
      },
      {
        id: 'ct-2',
        title: 'Ashen Ledger Retrieval',
        issuerFaction: 'embersynod',
        type: 'lore',
        regionId: regions[4]?.id || startRegion,
        status: 'available',
        progress: 0,
        steps: [
          { id: 'ct-2-s1', text: 'Locate the sealed archive chamber', done: false },
          { id: 'ct-2-s2', text: 'Bypass ward-lock signatures', done: false },
          { id: 'ct-2-s3', text: 'Return the ledger intact', done: false }
        ],
        branching: {
          riskPath: 'Break the ward lattice (faster but causes instability).',
          safePath: 'Decode ward phrases with Synod aid (requires negotiation).'
        },
        rewards: { medicine: 12, salvage: 20, reputation: { embersynod: 9 }, codexEntry: 'ashen-ledger-protocol' },
        failureConsequences: { reputation: { embersynod: -10, 'verdant-covenant': -6 }, morale: -4 },
        deadlineDay: 11
      }
    ];

    return {
      schemaVersion: SCHEMA_VERSION,
      expedition: {
        id: `exp-${Date.now()}`,
        name: 'Unnamed Expedition',
        commander: 'Field Commander',
        mode: 'expedition',
        status: 'active',
        createdAt: nowIso(),
        notes: ''
      },
      ui: {
        screen: CONFIG.ui.defaultScreen,
        iframeOpen: false,
        tutorialDismissed: false,
        commandHintShown: false
      },
      world: {
        seed,
        regions,
        discoveredRegions: [startRegion],
        currentLocation: startRegion,
        routeHistory: [startRegion],
        weather: {
          current: 'temperate wind',
          severity: 2,
          pressure: 'stable'
        },
        environment: {
          hazardLevel: 2,
          visibility: 'clear',
          anomalyDrift: 12
        }
      },
      time: {
        day: 1,
        hour: 7,
        turn: 0,
        phase: getDayPhase(7),
        totalHoursElapsed: 0
      },
      party: {
        roster: party,
        reserves: [],
        moraleAverage: Math.round(party.reduce((s, p) => s + p.morale, 0) / Math.max(1, party.length)),
        frictionIndex: 0,
        synergyIndex: 0
      },
      resources: {
        weightCapacity: 180,
        categories: {
          essentials: { food: 100, water: 110, medicine: 26 },
          materials: { salvage: 40, fuelCells: 18 },
          special: { relicShards: 0, signalKeys: 1 }
        },
        equipment: [
          { id: 'eq-1', name: 'Survey Drone Mk.II', assignedTo: party[0]?.id || null, utility: 'scouting', condition: 78 },
          { id: 'eq-2', name: 'Portable Medbench', assignedTo: party[1]?.id || null, utility: 'medicine', condition: 85 },
          { id: 'eq-3', name: 'Arc-Spike Kit', assignedTo: party[2]?.id || null, utility: 'engineering', condition: 64 }
        ],
        consumables: {
          rationRatePerTurn: 3,
          waterRatePerTurn: 3,
          medicineUseChance: 0.2
        }
      },
      factions,
      contracts: {
        active: baseContracts.filter((c) => c.status === 'active'),
        available: baseContracts.filter((c) => c.status === 'available'),
        completed: [],
        failed: []
      },
      codex: {
        entries: [
          { id: 'frontier-charter', title: 'Frontier Charter', unlockedAt: nowIso(), body: 'Expedition authority is provisional and contingent on delivered outcomes.' }
        ],
        discoveries: []
      },
      scene: {
        type: 'onboarding',
        summary: 'Initial staging and systems calibration.',
        promptFrame: '',
        continuityTags: ['boot', 'frontier']
      },
      events: {
        history: [],
        cooldowns: {},
        lastResolved: null
      },
      notifications: [],
      snapshots: [],
      debug: {
        enabled: false,
        lastDiagnostics: [],
        safetyFlags: {
          malformedRecoveries: 0,
          listenerGuardTriggered: false,
          timerCleanupCount: 0
        }
      },
      imagePipeline: {
        lastPrompt: '',
        queue: [],
        presets: {
          expedition: 'wide-angle expedition documentation, practical gear, weathered textures',
          landmark: 'architectural focus, environmental storytelling, atmospheric scale',
          factionPortrait: 'character portrait, faction insignia, practical frontier attire'
        }
      }
    };
  }

  function pushNotification(state, level, text) {
    state.notifications.push({ id: `ntf-${Date.now()}-${Math.floor(Math.random() * 9999)}`, level, text, at: nowIso(), seen: false });
    if (state.notifications.length > 80) {
      state.notifications = state.notifications.slice(state.notifications.length - 80);
    }
  }

  function logEvent(state, type, details) {
    state.events.history.push({
      id: `evt-${Date.now()}-${Math.floor(Math.random() * 9999)}`,
      turn: state.time.turn,
      day: state.time.day,
      hour: state.time.hour,
      type,
      details,
      at: nowIso()
    });
    if (state.events.history.length > CONFIG.sim.maxEventHistory) {
      state.events.history = state.events.history.slice(state.events.history.length - CONFIG.sim.maxEventHistory);
    }
  }

  function recalcPartyIndices(state) {
    const roster = state.party.roster || [];
    if (!roster.length) {
      state.party.moraleAverage = 0;
      state.party.frictionIndex = 0;
      state.party.synergyIndex = 0;
      return;
    }
    state.party.moraleAverage = Math.round(roster.reduce((sum, m) => sum + (m.morale || 0), 0) / roster.length);
    let relValues = [];
    for (const m of roster) {
      for (const key of Object.keys(m.relationships || {})) {
        relValues.push(m.relationships[key]);
      }
    }
    const avgRel = relValues.length ? relValues.reduce((a, b) => a + b, 0) / relValues.length : 0;
    state.party.frictionIndex = Math.round(clamp(-avgRel, 0, 100));
    state.party.synergyIndex = Math.round(clamp(avgRel + 50, 0, 100));
  }

  function getCurrentRegion(state) {
    return (state.world.regions || []).find((r) => r.id === state.world.currentLocation) || null;
  }

  function resolveTurnPassage(state, hours, mode) {
    const beforeDay = state.time.day;
    const beforeHour = state.time.hour;

    state.time.totalHoursElapsed += hours;
    state.time.hour += hours;
    while (state.time.hour >= 24) {
      state.time.hour -= 24;
      state.time.day += 1;
    }
    state.time.turn += 1;
    state.time.phase = getDayPhase(state.time.hour);

    const essentials = state.resources.categories.essentials;
    const rationDrain = Math.max(1, Math.round(state.resources.consumables.rationRatePerTurn * (hours / CONFIG.sim.campHoursBase)));
    const waterDrain = Math.max(1, Math.round(state.resources.consumables.waterRatePerTurn * (hours / CONFIG.sim.campHoursBase)));
    essentials.food = clamp(essentials.food - rationDrain, 0, CONFIG.resourceCaps.food);
    essentials.water = clamp(essentials.water - waterDrain, 0, CONFIG.resourceCaps.water);

    const weatherShift = Math.random() < 0.35;
    if (weatherShift) {
      const weatherStates = ['clear wind', 'dust storm', 'acid drizzle', 'fog banks', 'dry heat', 'cold front'];
      state.world.weather.current = pick(mulberry32(hashString(`${state.world.seed}|${state.time.turn}|w`)), weatherStates);
      state.world.weather.severity = clamp(state.world.weather.severity + (Math.random() > 0.5 ? 1 : -1), 1, 5);
      state.world.weather.pressure = state.world.weather.severity >= 4 ? 'volatile' : (state.world.weather.severity <= 2 ? 'stable' : 'shifting');
    }

    for (const member of state.party.roster) {
      member.fatigue = clamp(member.fatigue + (mode === 'travel' ? 9 : 2) + (state.world.weather.severity >= 4 ? 2 : 0), 0, 100);
      if (mode === 'camp') {
        member.fatigue = clamp(member.fatigue - 10, 0, 100);
        member.morale = clamp(member.morale + 2, 0, 100);
      } else {
        member.morale = clamp(member.morale - (state.world.weather.severity >= 4 ? 3 : 1), 0, 100);
      }
      if (member.fatigue > 82 && member.conditions.indexOf('exhausted') === -1) {
        member.conditions.push('exhausted');
      }
      if (member.fatigue < 60) {
        member.conditions = (member.conditions || []).filter((c) => c !== 'exhausted');
      }
    }

    if (essentials.food <= CONFIG.sim.lowSupplyWarningThreshold) {
      pushNotification(state, 'warning', 'Food reserves are critically low.');
    }
    if (essentials.water <= CONFIG.sim.lowSupplyWarningThreshold) {
      pushNotification(state, 'warning', 'Water reserves are critically low.');
    }

    recalcPartyIndices(state);
    logEvent(state, 'turn-pass', {
      mode,
      from: { day: beforeDay, hour: beforeHour },
      to: { day: state.time.day, hour: state.time.hour },
      weather: state.world.weather.current
    });
  }

  function applyFactionImpact(state, factionId, delta, reason) {
    const faction = state.factions[factionId];
    if (!faction) return;
    faction.reputation = clamp((faction.reputation || 0) + delta, -100, 100);
    faction.recentConsequences.push({ at: nowIso(), delta, reason });
    if (faction.recentConsequences.length > 20) {
      faction.recentConsequences = faction.recentConsequences.slice(faction.recentConsequences.length - 20);
    }
  }

  function getTravelRiskScore(state, destinationRegionId) {
    const current = getCurrentRegion(state);
    const destination = (state.world.regions || []).find((r) => r.id === destinationRegionId);
    if (!destination || !current) return 0;
    const weatherRisk = state.world.weather.severity * 4;
    const dangerRisk = destination.danger * 9;
    const fatigueRisk = Math.round((state.party.roster || []).reduce((s, m) => s + m.fatigue, 0) / Math.max(1, state.party.roster.length)) / 3;
    return Math.round(weatherRisk + dangerRisk + fatigueRisk);
  }

  function maybeTriggerEvent(state, mode) {
    const region = getCurrentRegion(state);
    if (!region) return null;

    const pool = mode === 'camp' ? region.encounterPools.camp : region.encounterPools.travel;
    const weighted = [];
    for (const eventId of pool) {
      const cooldownUntil = state.events.cooldowns[eventId] || -1;
      if (cooldownUntil > state.time.turn) continue;
      let weight = 10;
      if (eventId.indexOf('hostile') >= 0) weight += region.danger * 4;
      if (eventId.indexOf('weather') >= 0) weight += state.world.weather.severity * 3;
      if (eventId.indexOf('crew') >= 0) weight += state.party.frictionIndex / 8;
      if (eventId.indexOf('faction') >= 0) weight += 6;
      weighted.push({ eventId, weight });
    }
    if (!weighted.length) return null;

    const total = weighted.reduce((s, w) => s + w.weight, 0);
    let roll = Math.random() * total;
    let chosen = weighted[0].eventId;
    for (const w of weighted) {
      roll -= w.weight;
      if (roll <= 0) {
        chosen = w.eventId;
        break;
      }
    }

    state.events.cooldowns[chosen] = state.time.turn + CONFIG.sim.eventCooldownTurns;

    let outcome = '';
    if (chosen === 'landmark-discovery') {
      const discovery = region.notableLandmarks[Math.floor(Math.random() * region.notableLandmarks.length)];
      state.codex.discoveries.push({ id: `disc-${Date.now()}`, regionId: region.id, title: discovery, at: nowIso() });
      if (state.codex.discoveries.length > 120) {
        state.codex.discoveries = state.codex.discoveries.slice(state.codex.discoveries.length - 120);
      }
      outcome = `Discovery logged: ${discovery}.`;
      pushNotification(state, 'info', `Discovery in ${region.name}: ${discovery}.`);
    } else if (chosen === 'hostile-ambush' || chosen === 'hostile-scouts' || chosen === 'perimeter-breach') {
      const medUse = Math.random() < state.resources.consumables.medicineUseChance;
      if (medUse) {
        state.resources.categories.essentials.medicine = clamp(state.resources.categories.essentials.medicine - 1, 0, CONFIG.resourceCaps.medicine);
      }
      for (const member of state.party.roster) {
        if (Math.random() < 0.22) {
          member.conditions = member.conditions || [];
          if (member.conditions.indexOf('injured') === -1) member.conditions.push('injured');
          member.morale = clamp(member.morale - 5, 0, 100);
        }
      }
      applyFactionImpact(state, 'ironwardens', -2, 'Security lapse during hostile contact.');
      outcome = 'Hostile contact strained morale and consumed medical reserves.';
      pushNotification(state, 'warning', 'Hostile encounter resolved with minor injuries.');
    } else if (chosen === 'faction-envoy') {
      const f = pick(mulberry32(hashString(`${state.world.seed}|${state.time.turn}|envoy`)), Object.values(state.factions));
      applyFactionImpact(state, f.id, 4, 'Constructive camp parley.');
      outcome = `${f.name} envoy offered a limited accord.`;
      pushNotification(state, 'info', `Faction standing improved with ${f.name}.`);
    } else if (chosen === 'crew-reflection' || chosen === 'night-watch-incident' || chosen === 'minor-disturbance') {
      for (const member of state.party.roster) {
        member.morale = clamp(member.morale + (mode === 'camp' ? 1 : 0), 0, 100);
      }
      outcome = 'Crew dynamics shifted with no major material losses.';
    } else {
      outcome = 'Environmental disruption imposed route and time penalties.';
    }

    const result = { eventId: chosen, outcome, mode, regionId: region.id };
    state.events.lastResolved = result;
    logEvent(state, 'encounter', result);
    return result;
  }

  function ensureContractProgress(state) {
    for (const contract of state.contracts.active) {
      const completedSteps = contract.steps.filter((s) => s.done).length;
      contract.progress = Math.round((completedSteps / Math.max(1, contract.steps.length)) * 100);
      if (contract.progress >= 100 && contract.status !== 'completed') {
        contract.status = 'completed';
        state.contracts.completed.push(contract);
        pushNotification(state, 'success', `Contract completed: ${contract.title}`);
        for (const key of Object.keys(contract.rewards.reputation || {})) {
          applyFactionImpact(state, key, contract.rewards.reputation[key], `Contract reward: ${contract.title}`);
        }
      }
      if (state.time.day > contract.deadlineDay && contract.status === 'active') {
        contract.status = 'failed';
        state.contracts.failed.push(contract);
        pushNotification(state, 'warning', `Contract failed due to deadline: ${contract.title}`);
        for (const key of Object.keys(contract.failureConsequences.reputation || {})) {
          applyFactionImpact(state, key, contract.failureConsequences.reputation[key], `Contract failure: ${contract.title}`);
        }
      }
    }
    state.contracts.active = state.contracts.active.filter((c) => c.status === 'active');
  }

  function snapshotState(state, label) {
    const snap = {
      id: `snap-${Date.now()}`,
      label: label || `Snapshot D${state.time.day}T${state.time.turn}`,
      createdAt: nowIso(),
      payload: safeJsonClone(state, null)
    };
    if (!snap.payload) return null;
    state.snapshots.push(snap);
    if (state.snapshots.length > SNAPSHOT_LIMIT) {
      state.snapshots = state.snapshots.slice(state.snapshots.length - SNAPSHOT_LIMIT);
    }
    pushNotification(state, 'info', `Snapshot saved: ${snap.label}`);
    return snap;
  }

  function restoreSnapshot(state, snapshotId) {
    const snap = (state.snapshots || []).find((s) => s.id === snapshotId) || null;
    if (!snap) return null;
    const restored = safeJsonClone(snap.payload, null);
    if (!restored) return null;
    pushNotification(restored, 'info', `Restored snapshot: ${snap.label}`);
    return restored;
  }

  function buildHiddenSystemContext(state) {
    const region = getCurrentRegion(state);
    const essentials = state.resources.categories.essentials;
    const topContracts = state.contracts.active.slice(0, 2).map((c) => `${c.title} (${c.progress}%)`).join('; ') || 'none';
    const factionSummary = Object.values(state.factions).map((f) => `${f.name}:${f.reputation}`).join(' | ');
    const memberSummary = state.party.roster.map((m) => `${m.name}/${m.role}:morale${m.morale},fatigue${m.fatigue},conds[${(m.conditions || []).join(',') || 'none'}]`).join(' ; ');

    return [
      '[Chronicle Foundry Runtime Context]',
      `Expedition=${state.expedition.name} Commander=${state.expedition.commander}`,
      `Time=Day ${state.time.day} Hour ${state.time.hour} Phase ${state.time.phase} Turn ${state.time.turn}`,
      `Location=${region ? region.name : state.world.currentLocation} Biome=${region ? region.biome : 'unknown'} Danger=${region ? region.danger : '?'}`,
      `Weather=${state.world.weather.current} Severity=${state.world.weather.severity} Visibility=${state.world.environment.visibility}`,
      `Resources=Food ${essentials.food}, Water ${essentials.water}, Medicine ${essentials.medicine}, Salvage ${state.resources.categories.materials.salvage}`,
      `Party=${memberSummary}`,
      `Contracts=${topContracts}`,
      `Factions=${factionSummary}`,
      `RecentEvent=${state.events.lastResolved ? `${state.events.lastResolved.eventId}: ${state.events.lastResolved.outcome}` : 'none'}`,
      'NarrativeRules=Deliver coherent expedition command narration with operational summary + consequence-aware next options.'
    ].join('\n');
  }

  function renderStatusCard(state) {
    const region = getCurrentRegion(state);
    return [
      `Chronicle Foundry | Day ${state.time.day} ${state.time.hour}:00 (${state.time.phase})`,
      `Location: ${region ? region.name : state.world.currentLocation} | Weather: ${state.world.weather.current}`,
      `Food ${state.resources.categories.essentials.food} | Water ${state.resources.categories.essentials.water} | Medicine ${state.resources.categories.essentials.medicine}`,
      `Party morale avg ${state.party.moraleAverage} | Friction ${state.party.frictionIndex} | Synergy ${state.party.synergyIndex}`,
      `Active contracts: ${state.contracts.active.length} | Discoveries: ${state.codex.discoveries.length}`
    ].join('\n');
  }

  function commandHelpText() {
    return [
      'Chronicle Foundry commands:',
      '/help-engine — command list',
      '/status-engine — expedition status brief',
      '/travel <region-id> — execute travel turn to connected region',
      '/camp — execute camp turn',
      '/snapshot <label> — save snapshot',
      '/restore <snapshot-id> — restore snapshot',
      '/new-expedition <optional-seed> — hard reset to new world state',
      '/ui open | /ui close — toggle engine iframe',
      '/debug on | /debug off — toggle diagnostics'
    ].join('\n');
  }

  function postSystemToUser(text) {
    oc.thread.messages.push({
      author: 'system',
      content: text,
      hiddenFrom: ['ai'],
      expectsReply: false
    });
  }

  function injectHiddenContextForAi(state) {
    oc.thread.messages.push({
      author: 'system',
      content: buildHiddenSystemContext(state),
      hiddenFrom: ['user'],
      expectsReply: false
    });
  }

  function markMessageProcessed(message, key) {
    message.customData ??= {};
    const marker = `${NS}_processed_${key}`;
    if (message.customData[marker]) return false;
    message.customData[marker] = true;
    return true;
  }

  function parseCommand(text) {
    if (!text || text[0] !== '/') return null;
    const chunks = text.trim().split(/\s+/);
    const command = chunks.shift().toLowerCase();
    return { command, args: chunks };
  }

  function saveState(state) {
    ensureCoreObjects();
    const serial = safeJsonClone(state, null);
    if (!serial) return;
    oc.character.customData[NS] = serial;
    oc.character.customData.PUBLIC[STORAGE_KEY] = serial;
    oc.thread.customData[NS] = serial;
  }

  function migrateStateIfNeeded(state) {
    if (!state || typeof state !== 'object') return null;
    if (!state.schemaVersion) state.schemaVersion = 0;
    let migrated = state;

    if (migrated.schemaVersion < 1) {
      migrated.schemaVersion = 1;
      migrated.debug ??= { enabled: false, lastDiagnostics: [], safetyFlags: { malformedRecoveries: 0, listenerGuardTriggered: false, timerCleanupCount: 0 } };
      migrated.notifications ??= [];
    }

    return migrated;
  }

  function loadStateOrRecover() {
    ensureCoreObjects();
    const candidates = [
      oc.thread.customData[NS],
      oc.character.customData[NS],
      oc.character.customData.PUBLIC[STORAGE_KEY]
    ];

    for (const raw of candidates) {
      if (!raw) continue;
      try {
        const cloned = safeJsonClone(raw, null);
        if (!cloned) continue;
        const migrated = migrateStateIfNeeded(cloned);
        if (!migrated || !migrated.world || !migrated.party || !migrated.resources) continue;
        return migrated;
      } catch (_err) {
      }
    }

    const recovered = createDefaultState();
    recovered.debug.safetyFlags.malformedRecoveries += 1;
    return recovered;
  }

  function setDefaultShortcuts() {
    oc.thread.shortcutButtons = [
      { name: 'Status', message: '/status-engine', insertionType: 'replace', autoSend: true, clearAfterSend: true },
      { name: 'Camp', message: '/camp', insertionType: 'replace', autoSend: true, clearAfterSend: true },
      { name: 'Travel', message: '/travel rg-2', insertionType: 'replace', autoSend: false, clearAfterSend: false },
      { name: 'Snapshot', message: '/snapshot checkpoint', insertionType: 'replace', autoSend: true, clearAfterSend: true },
      { name: 'Help', message: '/help-engine', insertionType: 'replace', autoSend: true, clearAfterSend: true },
      { name: 'UI Open', message: '/ui open', insertionType: 'replace', autoSend: true, clearAfterSend: true }
    ];
  }

  function clearTimers() {
    while (TIMER_REGISTRY.length) {
      const id = TIMER_REGISTRY.pop();
      clearInterval(id);
      clearTimeout(id);
    }
  }

  function toggleUiWindow(state, shouldOpen) {
    state.ui.iframeOpen = !!shouldOpen;
    if (state.ui.iframeOpen) {
      oc.window.show();
      document.body.innerHTML = `<div style="font-family:system-ui,sans-serif;padding:14px;color:light-dark(#1f2937,#d1d5db);background:light-dark(#f9fafb,#111827);height:100%;box-sizing:border-box;">
        <h3 style="margin:0 0 8px 0;">Chronicle Foundry</h3>
        <pre style="white-space:pre-wrap;line-height:1.35;background:light-dark(#ffffff,#1f2937);padding:10px;border-radius:8px;border:1px solid light-dark(#d1d5db,#374151);">${renderStatusCard(state).replace(/</g, '&lt;')}</pre>
        <div style="font-size:12px;opacity:0.8;margin-top:8px;">Pass 1 foundation mode. Full expedition application shell expands in Pass 2.</div>
      </div>`;
    } else {
      oc.window.hide();
    }
  }

  function handleCommand(state, parsed) {
    const { command, args } = parsed;

    if (command === '/help-engine') {
      postSystemToUser(commandHelpText());
      return state;
    }

    if (command === '/status-engine') {
      postSystemToUser(renderStatusCard(state));
      return state;
    }

    if (command === '/debug') {
      const mode = (args[0] || '').toLowerCase();
      state.debug.enabled = mode === 'on';
      pushNotification(state, 'info', `Debug mode ${state.debug.enabled ? 'enabled' : 'disabled'}.`);
      postSystemToUser(`Debug mode ${state.debug.enabled ? 'enabled' : 'disabled'}.`);
      return state;
    }

    if (command === '/ui') {
      const mode = (args[0] || '').toLowerCase();
      if (mode === 'open') {
        toggleUiWindow(state, true);
        postSystemToUser('Engine UI opened.');
      } else if (mode === 'close') {
        toggleUiWindow(state, false);
        postSystemToUser('Engine UI closed.');
      } else {
        postSystemToUser('Usage: /ui open | /ui close');
      }
      return state;
    }

    if (command === '/snapshot') {
      const label = args.join(' ').trim() || undefined;
      const snap = snapshotState(state, label);
      postSystemToUser(snap ? `Snapshot stored: ${snap.id} (${snap.label})` : 'Snapshot failed.');
      return state;
    }

    if (command === '/restore') {
      const id = (args[0] || '').trim();
      if (!id) {
        postSystemToUser('Usage: /restore <snapshot-id>');
        return state;
      }
      const restored = restoreSnapshot(state, id);
      if (!restored) {
        postSystemToUser(`Snapshot not found: ${id}`);
        return state;
      }
      postSystemToUser(`Snapshot restored: ${id}`);
      return restored;
    }

    if (command === '/new-expedition') {
      const seed = args[0] ? `cf-${args[0]}` : undefined;
      const replacement = createDefaultState(seed);
      pushNotification(replacement, 'info', `New expedition initialized${seed ? ` with seed ${seed}` : ''}.`);
      postSystemToUser('New expedition initialized.');
      if (replacement.ui.iframeOpen) toggleUiWindow(replacement, true);
      return replacement;
    }

    if (command === '/travel') {
      const target = (args[0] || '').trim();
      if (!target) {
        postSystemToUser('Usage: /travel <region-id>');
        return state;
      }
      const current = getCurrentRegion(state);
      const destination = (state.world.regions || []).find((r) => r.id === target);
      if (!destination) {
        postSystemToUser(`Unknown region: ${target}`);
        return state;
      }
      if (!current || current.neighbors.indexOf(destination.id) === -1) {
        postSystemToUser(`Travel blocked: ${destination.id} is not directly connected to current region.`);
        return state;
      }

      const risk = getTravelRiskScore(state, destination.id);
      state.world.currentLocation = destination.id;
      if (state.world.discoveredRegions.indexOf(destination.id) === -1) {
        state.world.discoveredRegions.push(destination.id);
      }
      state.world.routeHistory.push(destination.id);
      resolveTurnPassage(state, CONFIG.sim.simTravelHoursBase || CONFIG.sim.travelHoursBase, 'travel');
      const event = maybeTriggerEvent(state, 'travel');
      ensureContractProgress(state);
      state.scene = {
        type: 'travel-hardship',
        summary: `Transit into ${destination.name} completed with risk score ${risk}.`,
        promptFrame: event ? `${event.eventId}: ${event.outcome}` : 'No major contact.',
        continuityTags: ['travel', destination.biome, `danger-${destination.danger}`]
      };
      postSystemToUser(`Travel resolved to ${destination.name}. Risk ${risk}.${event ? ` Event: ${event.eventId}.` : ''}`);
      return state;
    }

    if (command === '/camp') {
      resolveTurnPassage(state, CONFIG.sim.campHoursBase, 'camp');
      const event = maybeTriggerEvent(state, 'camp');
      ensureContractProgress(state);
      state.scene = {
        type: 'camp-reflection',
        summary: 'Camp operations completed with crew decompression and maintenance actions.',
        promptFrame: event ? `${event.eventId}: ${event.outcome}` : 'Camp remained stable.',
        continuityTags: ['camp', 'reflection', state.world.weather.current]
      };
      postSystemToUser(`Camp turn resolved.${event ? ` Event: ${event.eventId}.` : ''}`);
      return state;
    }

    postSystemToUser(`Unknown engine command: ${command}. Use /help-engine.`);
    return state;
  }

  ensureCoreObjects();
  clearTimers();

  let state = loadStateOrRecover();
  state = migrateStateIfNeeded(state) || createDefaultState();

  state.ui ??= { screen: CONFIG.ui.defaultScreen, iframeOpen: false, tutorialDismissed: false, commandHintShown: false };
  state.world ??= createDefaultState().world;
  state.party ??= createDefaultState().party;
  state.resources ??= createDefaultState().resources;
  state.factions ??= createDefaultState().factions;
  state.contracts ??= createDefaultState().contracts;
  state.events ??= { history: [], cooldowns: {}, lastResolved: null };
  state.notifications ??= [];
  state.snapshots ??= [];
  state.debug ??= { enabled: false, lastDiagnostics: [], safetyFlags: { malformedRecoveries: 0, listenerGuardTriggered: false, timerCleanupCount: 0 } };
  recalcPartyIndices(state);

  setDefaultShortcuts();
  toggleUiWindow(state, false);

  if (!state.ui.commandHintShown) {
    postSystemToUser('Chronicle Foundry initialized. Use /help-engine for controls and /status-engine for operational state.');
    state.ui.commandHintShown = true;
  }

  saveState(state);

  oc.thread.on('MessageAdded', async ({ message }) => {
    try {
      if (!message || !markMessageProcessed(message, 'main')) return;
      if (message.author !== 'user') return;

      const text = String(message.content || '').trim();
      const parsed = parseCommand(text);

      if (parsed) {
        const index = oc.thread.messages.indexOf(message);
        if (index >= 0) oc.thread.messages.splice(index, 1);
        state = handleCommand(state, parsed);
        saveState(state);
        return;
      }

      injectHiddenContextForAi(state);
      saveState(state);
    } catch (err) {
      state.debug.safetyFlags.listenerGuardTriggered = true;
      pushNotification(state, 'error', `Engine handler recovered from error: ${String(err && err.message || err)}`);
      saveState(state);
      if (state.debug.enabled) {
        postSystemToUser(`Debug: handler recovery triggered (${String(err && err.message || err)}).`);
      }
    }
  });

  const autoSnapshotTimer = setInterval(() => {
    try {
      state = loadStateOrRecover();
      if ((state.time.turn || 0) > 0 && (state.time.turn % 8 === 0)) {
        snapshotState(state, `Auto D${state.time.day}T${state.time.turn}`);
      }
      saveState(state);
    } catch (_err) {
    }
  }, 90000);
  TIMER_REGISTRY.push(autoSnapshotTimer);
})();
